import { Dimensions } from 'react-native';

const { width: screenWidth } = Dimensions.get('window');
const referenceWidth = 375; // Largeur de référence (iPhone SE)

export const responsiveWidth = (size) => {
  return (screenWidth / referenceWidth) * size;
};

// Utilisation : <View style={{ margin: responsiveWidth(20) }} />

import { useWindowDimensions } from 'react-native';

const useResponsive = () => {
  const { width } = useWindowDimensions();
  const referenceWidth = 375;

  const responsive = (size) => (width / referenceWidth) * size;

  return { responsive, screenWidth: width };
};

// Utilisation
const MyComponent = () => {
  const { responsive } = useResponsive();
  return &lt;View style={{ margin: responsive(20), padding: responsive(16) }} /&gt;;
};
